import { mkdir, writeFile } from "node:fs/promises";
import { dirname, relative } from "node:path";
import { fileURLToPath } from "node:url";
import { build } from "esbuild";

const root = dirname(dirname(fileURLToPath(import.meta.url)));
const outFile = `${root}/src/generated/client-assets.ts`;

const bundles = await Promise.all([
  bundle("homeClientScript", `${root}/src/frontend/home.client.ts`),
  bundle("auditClientScript", `${root}/src/frontend/audit.client.ts`)
]);

await mkdir(dirname(outFile), { recursive: true });
await writeFile(
  outFile,
  [
    "// This file is generated by scripts/build-client-assets.mjs.",
    "// Edit src/frontend/*.client.ts instead.",
    ...bundles
  ].join("\n\n") + "\n"
);

async function bundle(exportName, entryPoint) {
  const result = await build({
    entryPoints: [entryPoint],
    bundle: true,
    format: "iife",
    platform: "browser",
    target: "es2022",
    write: false,
    logLevel: "silent"
  });
  const source = result.outputFiles[0].text;
  const sourcePath = relative(root, entryPoint);

  return `export const ${exportName} = ${JSON.stringify(source)};\n// Source: ${sourcePath}`;
}

